import React, { useState } from 'react';
import Navbar from './Navbar';
import CircularProgress from '@mui/material/CircularProgress';
import Footer from './Footer';

const BGPLLaMa = () => {
    const [query, setQuery] = useState('');
    const [output, setOutput] = useState('');
    const [isLoading, setIsLoading] = useState(false);

    const handleQuerySubmit = (event) => {
        event.preventDefault();
        if (!query.trim()) {
            alert('Please provide a query.');
            return;
        }
        setOutput(''); // Clear previous output
        setIsLoading(true);
        const eventSource = new EventSource(`http://127.0.0.1:8000/api/bgp-llama?query=${encodeURIComponent(query)}`);

        eventSource.onmessage = function(event) {
            const data = JSON.parse(event.data);
            if (data.text) {
                setOutput(prevOutput => prevOutput + data.text);
            }
        };

        eventSource.onerror = function() {
            eventSource.close();
            setIsLoading(false);
        };

        // To close the event source when the component unmounts
        return () => {
            eventSource.close();
        };
    };

    return (
        <div className="flex flex-col h-screen justify-between">
            <Navbar />
            <main className="mb-auto p-4">
                <div className="container mx-auto">
                    <div className="flex justify-between">
                        <div className="w-2/3 ml-4">
                            <h2 className="font-bold mb-2">Welcome to BGP-LLaMA</h2>
                            <p className="mb-4">Enter your query in the text box below.</p>
                            <form onSubmit={handleQuerySubmit}>
                                <div className="mb-4">
                                    <label htmlFor="queryInput" className="block mb-2">Prompt</label>
                                    <textarea
                                        id="queryInput"
                                        rows="4"
                                        className="w-full border p-2"
                                        placeholder="Enter your query here"
                                        value={query}
                                        onChange={(e) => setQuery(e.target.value)}
                                    />
                                </div>
                                {isLoading ? (
                                    <CircularProgress />
                                ) : (
                                    <button
                                        type="submit"
                                        className="bg-gray-700 hover:bg-gray-500 text-white font-bold py-2 px-4 rounded"
                                    >
                                        Submit
                                    </button>
                                )}
                            </form>
                            {output && (
                                <div className="mt-4">
                                    <h3 className="font-bold mb-2">Model Output:</h3>
                                    <div className="border p-2 overflow-x-auto">
                                        <pre className="whitespace-pre-wrap"><code>{output}</code></pre>
                                    </div>
                                </div>
                            )}
                        </div>
                    </div>
                </div>
            </main>
            <Footer />
        </div>
    );
};

export default BGPLLaMa;
